const campaignDurationWeeks = inputs.campaignDurationWeeks;
const numCoreOrganizers = inputs.numCoreOrganizers;
const numExpectedParticipants = inputs.numExpectedParticipants;
const protestFrequencyPerMonth = inputs.protestFrequencyPerMonth;
const legalAidHours = inputs.legalAidHours;
const digitalAdBudgetPerWeek = inputs.digitalAdBudgetPerWeek;
const printMaterialBudgetPerMonth = inputs.printMaterialBudgetPerMonth;
const educationalEventCount = inputs.educationalEventCount;

// Constants for cost estimation
const AVG_PROTEST_SUPPLY_PER_PARTICIPANT = 4; // Cost for posters, water, basic first aid per person
const AVG_PERMIT_COST_PER_PROTEST = 120; // Average permit/site fee cost
const AVG_LEGAL_HOURLY_RATE = 200; // Estimated value of legal aid per hour (even if pro bono, for resource estimation)
const AVG_EDUCATIONAL_EVENT_COST = 200; // Cost for room, basic materials, refreshments
const ORGANIZER_BASE_HOURS_PER_WEEK = 15; // Base hours per organizer per week
const ORGANIZER_PROTEST_ADDITIONAL_HOURS_PER_PROTEST = 8; // Additional hours per organizer for protest prep/execution

// Cap inputs for realistic calculations and prevent extreme values
const cappedParticipants = Math.min(numExpectedParticipants, 10000); 
const cappedLegalAidHours = Math.min(legalAidHours, 1000); 
const cappedEducationalEventCount = Math.min(educationalEventCount, 50); 

// 1. Protest Logistics Cost
const totalProtests = Math.ceil(protestFrequencyPerMonth * (campaignDurationWeeks / 4.33)); // Approx 4.33 weeks per month
const costPerProtest = AVG_PERMIT_COST_PER_PROTEST + (cappedParticipants * AVG_PROTEST_SUPPLY_PER_PARTICIPANT);
let protestLogisticsCost = 0;
if (totalProtests > 0) {
    protestLogisticsCost = totalProtests * costPerProtest;
}

// 2. Legal Support Cost
let legalSupportCost = 0;
if (cappedLegalAidHours > 0) {
    legalSupportCost = cappedLegalAidHours * AVG_LEGAL_HOURLY_RATE;
}

// 3. Communication & Outreach Cost
const digitalAdCost = digitalAdBudgetPerWeek * campaignDurationWeeks;
const printMaterialCost = printMaterialBudgetPerMonth * (campaignDurationWeeks / 4.33); // Convert monthly budget to weekly for duration
const communicationOutreachCost = digitalAdCost + printMaterialCost;

// 4. Educational Events Cost
let educationalEventsCost = 0;
if (cappedEducationalEventCount > 0) {
    educationalEventsCost = cappedEducationalEventCount * AVG_EDUCATIONAL_EVENT_COST;
}

// 5. Organizer Support Hours
const baseOrganizerHours = numCoreOrganizers * campaignDurationWeeks * ORGANIZER_BASE_HOURS_PER_WEEK;
const protestRelatedOrganizerHours = numCoreOrganizers * totalProtests * ORGANIZER_PROTEST_ADDITIONAL_HOURS_PER_PROTEST;
const organizerSupportHours = baseOrganizerHours + protestRelatedOrganizerHours;

// Total Estimated Cost
const totalEstimatedCost = protestLogisticsCost + legalSupportCost + communicationOutreachCost + educationalEventsCost;

return {
    totalEstimatedCost: totalEstimatedCost,
    protestLogisticsCost: protestLogisticsCost,
    legalSupportCost: legalSupportCost,
    communicationOutreachCost: communicationOutreachCost,
    educationalEventsCost: educationalEventsCost,
    organizerSupportHours: organizerSupportHours,
};
